INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4b4f8d26-68d5-406b-8efc-b68d4dac9d0c',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions vs GitLab CI — Mapping Stages, Artifacts, Cache, Runners, and Templates$escape$,
  $escape$GitLab CI's pipeline model maps cleanly to GitHub Actions, but the abstractions differ. Where GitLab uses `stages:` to enforce job ordering, GitHub Actions uses `needs:` per job — expressing an explicit dependency graph (DAG) rather than a flat stage list.

Artifacts become `actions/upload-artifact@v4` and `actions/download-artifact@v4`. Reference them by `name` across jobs; they're automatically scoped to the workflow run. Caching uses `actions/cache@v4` with a `key` + `restore-keys` fallback chain, mirroring GitLab's `cache.key` + `cache.policy`.

For runners, self-hosted GitHub runners replace GitLab's custom runners — tagged via `runs-on: [self-hosted, linux, x64]` instead of GitLab's `tags:`. GitHub-hosted runners (`ubuntu-latest`, `macos-latest`) have no direct GitLab equivalent.

GitLab's `include:` templates become reusable workflows (triggered via `workflow_call`) or composite actions. A reusable workflow lives in `.github/workflows/` and is invoked with `uses: org/repo/.github/workflows/shared.yml@main`, accepting typed `inputs` via `with:`. This is the idiomatic way to share pipeline logic across repositories without copy-pasting YAML.$escape$,
  $escape$jobs:
  build:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/cache@v4
        with:
          path: ~/.npm
          key: ${{ runner.os }}-${{ hashFiles('**/package-lock.json') }}
      - run: npm ci && npm run build
      - uses: actions/upload-artifact@v4
        with: { name: dist, path: dist/ }
  deploy:
    needs: build  # replaces GitLab stages ordering
    runs-on: [self-hosted, linux]  # replaces GitLab runner tags
    steps:
      - uses: actions/download-artifact@v4
        with: { name: dist }$escape$,
  $escape$bash$escape$,
