INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e048e8d5-6ce0-462a-bf92-58833244a986',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions Parallelization — Matrix Builds, Parallel Jobs, and Test Sharding$escape$,
  $escape$GitHub Actions runs jobs concurrently by default when they have no `needs` dependency. Combine this with `strategy.matrix` to fan out builds across OS, runtime version, or any arbitrary dimension — each combination spawns an independent runner. For test sharding, pair matrix with `--shard` flags (Jest, Vitest, Playwright all support it): split your suite into N slices and run each slice on its own runner, cutting wall-clock time proportionally. Use `strategy.fail-fast: false` so a failing shard doesn't cancel sibling runners prematurely — you want the full failure picture. Cap concurrency with `strategy.max-parallel` to stay within your runner quota. For reusable parallelism patterns, extract logic into a reusable workflow called via `workflow_call` and invoke it with a matrix from the parent. One sharp edge: `upload-artifact` calls from parallel jobs must use unique `name` values or they'll collide. Use `${{ matrix.shard }}` in the artifact name. On large monorepos, combine this with `paths` filters on `on.push` to only trigger the relevant job matrix.$escape$,
  $escape$jobs:
  test:
    strategy:
      fail-fast: false
      max-parallel: 4
      matrix:
        shard: [1, 2, 3, 4]
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - run: npx vitest run --reporter=junit --shard=${{ matrix.shard }}/${{ strategy.job-total }}
      - uses: actions/upload-artifact@v4
        with:
          name: test-results-shard-${{ matrix.shard }}
          path: junit.xml$escape$,
  $escape$bash$escape$,
