INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'aa4a9d1b-74d4-407b-bcc9-8519f4a97ace',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions GitOps — Git as Your Deployment Truth$escape$,
  $escape$GitOps treats your repository as the single source of truth for infrastructure and application state. With GitHub Actions, you enforce this by triggering deployments exclusively on pushes to protected branches — never via manual kubectl or ad-hoc scripts.

The pattern: a `deploy.yml` workflow fires on `push` to `main`, reads Kubernetes manifests from `./k8s/`, and applies them via `kubectl apply -f`. The cluster converges to whatever is committed. No drift, no undocumented hotfixes.

Crucial enforcement: lock your workflow with `environment: production` and set required reviewers in GitHub's Environment settings. This adds an approval gate before the `kubectl` step runs, giving you audit trails via Actions logs.

For image tag management, avoid `latest`. Instead, use `${{ github.sha }}` to tag images and patch the manifest inline with `kustomize edit set image`. Commit that back to the repo — now the deployed SHA is always traceable in git history.

Pair with `on: pull_request` to run `kubectl diff` as a dry-run check, surfacing cluster delta before merge. Your PR becomes a deployment preview.$escape$,
  $escape$name: GitOps Deploy
on:
  push:
    branches: [main]
jobs:
  deploy:
    runs-on: ubuntu-latest
    environment: production
    steps:
      - uses: actions/checkout@v4
      - name: Patch image tag
        run: |
          cd k8s
          kustomize edit set image app=ghcr.io/${{ github.repository }}:${{ github.sha }}
      - name: Apply manifests
        run: kubectl apply -k k8s/
        env:
          KUBECONFIG_DATA: ${{ secrets.KUBECONFIG }}
      - name: Commit updated manifest
        run: |
          git config user.email "ci@byteai.dev"
          git config user.name "GitHub Actions"
          git add k8s/kustomization.yaml
          git commit -m "chore: deploy ${{ github.sha }}" && git push || true$escape$,
  $escape$bash$escape$,
