INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ee5613e9-f523-49d7-aeb8-c80890cccf2d',
  '00000000-0000-0000-0000-000000000001',
  $escape$GitHub Actions Monorepo CI — Affected Detection with Turborepo and NX$escape$,
  $escape$Running full CI on every push in a monorepo burns minutes and money. GitHub Actions has no native affected detection, but Turborepo and NX fill the gap by hashing inputs and comparing against a baseline ref.

With Turborepo, set `TURBO_TOKEN` and `TURBO_TEAM` secrets to enable Remote Caching. Add `--filter=[HEAD^1]` to `turbo run test build` — Turborepo diffs against the previous commit and skips unchanged packages. For PRs, use `--filter=[origin/main...HEAD]` to scope against the base branch.

NX offers `nx affected --base=origin/main --head=HEAD` with a `--target=test` flag. Pair it with the `nrwl/nx-set-shas@v4` action to automatically compute `NX_BASE` and `NX_HEAD` from PR context, including merge-base resolution.

Both tools integrate with GitHub Actions' `paths` filter for coarse-grained gating (skip CI entirely when only docs change), then apply fine-grained affected logic inside the job. Use `actions/cache@v4` to persist `.turbo` or `.nx/cache` between runs, or lean on their hosted remote caches for cross-machine hit rates above 80%.$escape$,
  $escape$- uses: nrwl/nx-set-shas@v4
  id: setSHAs

- name: Run affected tests
  run: |
    npx nx affected \
      --target=test \
      --base=${{ steps.setSHAs.outputs.base }} \
      --head=${{ steps.setSHAs.outputs.head }} \
      --parallel=3
  env:
    NX_CLOUD_ACCESS_TOKEN: ${{ secrets.NX_CLOUD_ACCESS_TOKEN }}$escape$,
  $escape$bash$escape$,
